#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int X; scanf("%d", &X);
        int remaining = 100 - X;
        int ans = remaining - (remaining % 10);
        if(ans < 0) ans = 0;
        printf("%d\n", ans);
    }
    return 0;
}

